#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    for(int tc=0; tc<T; ++tc){
        int N; scanf("%d",&N);
        for(int cur=N; cur>=0; --cur){
            int h = cur/3600;
            int m = (cur%3600)/60;
            int s = cur%60;
            printf("%02d:%02d:%02d\n",h,m,s);
        }
        if(tc!=T-1) printf("\n");
    }
    return 0;
}

